sys_script.script:
/**
 * Before Update: Validates state transitions on Consumer Cases.
 * Prevents invalid transitions and aborts with an error message.
 *
 * Valid transitions:
 *   -5 (Pending) -> 1 (Open), 2 (Work in Progress)
 *   1 (Open) -> 2 (Work in Progress), -5 (Pending)
 *   2 (Work in Progress) -> 3 (Closed Complete), 4 (Closed Incomplete), 7 (Closed Skipped), -5 (Pending), 1 (Open)
 *   3 (Closed Complete/Resolved) -> 2 (Reopen to WIP), 7 (Closed Skipped)
 *   4 (Closed Incomplete) -> 2 (Reopen to WIP)
 *   7 (Closed Skipped/Final) -> no transitions allowed
 *
 * Globals: current, previous, gs
 */
(function executeRule(current, previous) {
    var oldState = previous.getValue('state');
    var newState = current.getValue('state');

    // No change - nothing to validate
    if (oldState == newState) {
        return;
    }

    // Define valid transitions map
    var validTransitions = {
        '-5': ['1', '2'],
        '1': ['2', '-5'],
        '2': ['3', '4', '7', '-5', '1'],
        '3': ['2', '7'],
        '4': ['2'],
        '7': []
    };

    var allowed = validTransitions[oldState];
    if (!allowed) {
        // Unknown old state - allow the transition
        return;
    }

    if (allowed.indexOf(newState) === -1) {
        var stateLabels = {
            '-5': 'Pending',
            '1': 'Open',
            '2': 'Work in Progress',
            '3': 'Closed Complete',
            '4': 'Closed Incomplete',
            '7': 'Closed'
        };

        var fromLabel = stateLabels[oldState] || oldState;
        var toLabel = stateLabels[newState] || newState;

        gs.addErrorMessage(
            'Invalid state transition: Cannot move from "' + fromLabel + '" to "' + toLabel + '". ' +
            'Please follow the correct workflow sequence.'
        );
        current.setAbortAction(true);
    }
})(current, previous);
